using System;
using System.Reflection;
using System.Linq;

// Load the assemblies
var agentDll = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net8.0/Microsoft.Agents.AI.dll");
var extAiDll = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net8.0/Microsoft.Extensions.AI.dll");
var absAiDll = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.0/lib/net8.0/Microsoft.Extensions.AI.Abstractions.dll");

// Find key types
Console.WriteLine("=== KEY TYPES IN MICROSOFT.AGENTS.AI ===\n");
var chatClientAgent = agentDll.GetType("Microsoft.Agents.AI.ChatClientAgent");
PrintType(chatClientAgent);

var chatClientAgentOptions = agentDll.GetType("Microsoft.Agents.AI.ChatClientAgentOptions");
PrintType(chatClientAgentOptions);

var chatClientAgentRunOptions = agentDll.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions");
PrintType(chatClientAgentRunOptions);

Console.WriteLine("\n=== KEY TYPES IN MICROSOFT.EXTENSIONS.AI.ABSTRACTIONS ===\n");
var aiTool = absAiDll.GetType("Microsoft.Extensions.AI.AITool");
PrintType(aiTool);

var chatOptions = absAiDll.GetType("Microsoft.Extensions.AI.ChatOptions");
PrintType(chatOptions);

var iChatClient = absAiDll.GetType("Microsoft.Extensions.AI.IChatClient");
if (iChatClient != null)
{
    Console.WriteLine($"Interface: {iChatClient.FullName}");
    var methods = iChatClient.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    foreach (var method in methods)
    {
        var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  - {method.ReturnType.Name} {method.Name}({@params})");
    }
}

void PrintType(Type type)
{
    if (type == null)
    {
        Console.WriteLine("  [Type not found]");
        return;
    }

    Console.WriteLine($"Class: {type.FullName}");

    var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    if (ctors.Length > 0)
    {
        Console.WriteLine("  Constructors:");
        foreach (var ctor in ctors)
        {
            var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    - {type.Name}({@params})");
        }
    }

    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    if (props.Length > 0)
    {
        Console.WriteLine("  Properties:");
        foreach (var prop in props.Take(10))
        {
            var access = (prop.CanGet ? "get;" : "") + (prop.CanSet ? "set;" : "");
            Console.WriteLine($"    - {prop.PropertyType.Name} {prop.Name} {{ {access} }}");
        }
    }

    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    if (methods.Length > 0)
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.Take(8))
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    - {method.ReturnType.Name} {method.Name}({@params})");
        }
    }

    Console.WriteLine();
}
EOF
