using System.Reflection;

// Find AgentResponse in abstractions
var absAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name == "Microsoft.Agents.AI.Abstractions");
if (absAsm == null)
{
    // Load it
    var agentType = typeof(Microsoft.Agents.AI.ChatClientAgent);
    absAsm = agentType.Assembly;
}

var arType = absAsm?.GetType("Microsoft.Agents.AI.AgentResponse") 
    ?? typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly.GetType("Microsoft.Agents.AI.AgentResponse");

if (arType != null)
{
    Console.WriteLine($"=== {arType.FullName} ===");
    foreach (var p in arType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");
    foreach (var m in arType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  Method: {m.ReturnType.Name} {m.Name}()");
}
else
{
    // Search all loaded assemblies
    foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
    {
        var t = asm.GetTypes().FirstOrDefault(tt => tt.Name == "AgentResponse");
        if (t != null)
        {
            Console.WriteLine($"Found in: {asm.GetName().Name}");
            foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
                Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");
            break;
        }
    }
}

// Also check the Microsoft.Extensions.AI.OpenAI package for the extension method
Console.WriteLine("\n=== OpenAI ChatClient builder ===");
var openaiAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name?.Contains("OpenAI") == true);
Console.WriteLine($"OpenAI assembly: {openaiAsm?.GetName().Name}");
CSHARP
