cat > Program.cs << 'CSHARP'
using System.Reflection;

// Load the MEAI.OpenAI assembly
var openaiMeaiAsm = Assembly.LoadFrom(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) + 
    "/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll");

Console.WriteLine("=== Types in Microsoft.Extensions.AI.OpenAI ===");
foreach (var t in openaiMeaiAsm.GetExportedTypes())
{
    Console.WriteLine($"\n{t.FullName}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {(m.IsStatic ? "static " : "")}{m.ReturnType.Name} {m.Name}({parms})");
    }
}
