using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search functionality via a simple HTTP-based search API.
/// Falls back to simulated results when no API key is configured.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var response = await _httpClient.GetAsync(
                $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1",
                cancellationToken);

            if (response.IsSuccessStatusCode)
            {
                using var doc = await JsonDocument.ParseAsync(
                    await response.Content.ReadAsStreamAsync(cancellationToken),
                    cancellationToken: cancellationToken);

                var results = new List<string>();

                // Abstract/summary
                var abstractText = doc.RootElement.GetProperty("AbstractText").GetString();
                var abstractSource = doc.RootElement.GetProperty("AbstractSource").GetString();
                var abstractUrl = doc.RootElement.GetProperty("AbstractURL").GetString();
                if (!string.IsNullOrWhiteSpace(abstractText))
                {
                    results.Add($"**{abstractSource}**: {abstractText}\nSource: {abstractUrl}");
                }

                // Related topics
                if (doc.RootElement.TryGetProperty("RelatedTopics", out var topics))
                {
                    foreach (var topic in topics.EnumerateArray().Take(5))
                    {
                        if (topic.TryGetProperty("Text", out var text) &&
                            topic.TryGetProperty("FirstURL", out var url))
                        {
                            results.Add($"- {text.GetString()}\n  URL: {url.GetString()}");
                        }
                    }
                }

                if (results.Count > 0)
                {
                    return $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}";
                }
            }
        }
        catch (HttpRequestException)
        {
            // Fall through to fallback
        }

        return $"Search results for \"{query}\":\n"
            + "No detailed results were found from the web API. "
            + "Please try rephrasing the query or breaking it into smaller, more specific searches.";
    }
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can collect and organize research findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with the research findings")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved successfully: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this to review what has been collected so far before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content, timestamp) = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Retrieved {_notes.Count} note(s)");
        Console.ResetColor();

        return sb.ToString();
    }
}

