using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can collect and organize research findings.
/// </summary>
public sealed class NoteTool
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with the research findings")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved successfully: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this to review collected findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content, timestamp) = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Retrieved {_notes.Count} note(s)");
        Console.ResetColor();

        return sb.ToString();
    }
}

