using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var webSearch = new WebSearchTool();
var notes = new NoteTool();

// --- Register tools via AIFunctionFactory ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetNotes),
};

// --- Create the research agent ---
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research assistant. Your job is to research a topic thoroughly and produce a clear summary.

        Follow this workflow:
        1. Break the topic into 2-3 specific search queries.
        2. Use the SearchWeb tool to search for each query.
        3. Use the SaveNote tool to record the key findings from each search.
        4. After gathering enough information, use the GetNotes tool to review all your notes.
        5. Produce a well-structured summary with sections, key facts, and source URLs.

        Be concise but thorough. Always cite sources.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬 Research Agent                 ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine($"Researching: {topic}");
Console.ResetColor();
Console.WriteLine(new string('─', 50));

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine();
Console.WriteLine(new string('═', 50));
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("📄 RESEARCH SUMMARY");
Console.ResetColor();
Console.WriteLine(new string('═', 50));
Console.WriteLine();
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"[Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}]");
    Console.ResetColor();
}

